import { useState, useEffect } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';

const API = "https://team-task-manager-4-7vl7.onrender.com";
export default function Tasks() {
  const [tasks, setTasks] = useState([]);
  const [form, setForm] = useState({
    title: '', description: '', priority: 'Medium', dueDate: ''
  });
  const [error, setError] = useState('');
  const { projectId } = useParams();
  const token = localStorage.getItem('token');
  const navigate = useNavigate();

  useEffect(() => { fetchTasks(); }, []);

  const fetchTasks = async () => {
    try {
      const res = await axios.get(
        `${API}/api/tasks/${projectId}`,
        { headers: { Authorization: `Bearer ${token}` }}
      );
      setTasks(res.data);
    } catch (err) { console.error(err); }
  };

  const createTask = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API}/api/tasks`,
        { ...form, projectId },
        { headers: { Authorization: `Bearer ${token}` }}
      );
      setForm({ title:'', description:'',
        priority:'Medium', dueDate:'' });
      fetchTasks();
    } catch (err) {
      setError(err.response?.data?.message || 'Error!');
    }
  };

  const updateStatus = async (taskId, status) => {
    try {
      await axios.put(
        `${API}/api/tasks/${taskId}/status`,
        { status },
        { headers: { Authorization: `Bearer ${token}` }}
      );
      fetchTasks();
    } catch (err) { console.error(err); }
  };

  const getStatusColor = (status) => {
    if (status === 'Done') return '#27AE60';
    if (status === 'In Progress') return '#E67E22';
    return '#3498DB';
  };

  return (
    <div style={styles.container}>
      <div style={styles.navbar}>
        <h2 style={{color:'white', margin:0}}>📋 Tasks</h2>
        <button onClick={() => navigate('/dashboard')}
          style={styles.backBtn}>← Dashboard</button>
      </div>

      <div style={styles.content}>
        <div style={styles.formCard}>
          <h3>➕ Create New Task</h3>
          {error && <p style={{color:'red'}}>{error}</p>}
          <form onSubmit={createTask}>
            <input style={styles.input}
              placeholder="Task Title"
              value={form.title}
              onChange={e => setForm({...form, title: e.target.value})}
              required />
            <textarea style={styles.input}
              placeholder="Description"
              value={form.description}
              onChange={e => setForm({...form, description: e.target.value})}
              rows={2} />
            <select style={styles.input}
              value={form.priority}
              onChange={e => setForm({...form, priority: e.target.value})}>
              <option>Low</option>
              <option>Medium</option>
              <option>High</option>
            </select>
            <input style={styles.input}
              type="date"
              value={form.dueDate}
              onChange={e => setForm({...form, dueDate: e.target.value})} />
            <button style={styles.btn} type="submit">
              Create Task
            </button>
          </form>
        </div>

        <div style={styles.taskList}>
          <h3>All Tasks ({tasks.length})</h3>
          {tasks.map(task => (
            <div key={task._id} style={styles.taskCard}>
              <div style={{display:'flex',
                justifyContent:'space-between',
                alignItems:'center'}}>
                <h4 style={{margin:0}}>{task.title}</h4>
                <span style={{
                  background: getStatusColor(task.status),
                  color:'white', padding:'3px 10px',
                  borderRadius:20, fontSize:12
                }}>{task.status}</span>
              </div>
              <p style={{color:'#666', margin:'8px 0'}}>
                {task.description}
              </p>
              <div style={{display:'flex', gap:8, marginTop:8}}>
                <select
                  value={task.status}
                  onChange={e => updateStatus(task._id, e.target.value)}
                  style={styles.select}>
                  <option>To Do</option>
                  <option>In Progress</option>
                  <option>Done</option>
                </select>
                <span style={styles.priority}>
                  {task.priority}
                </span>
              </div>
            </div>
          ))}
          {tasks.length === 0 && (
            <p style={{color:'#888', textAlign:'center'}}>
              No tasks yet! Create one above.
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  container: { minHeight:'100vh', background:'#f4f6f7' },
  navbar: { background:'#0A2342', padding:'15px 30px',
    display:'flex', justifyContent:'space-between',
    alignItems:'center' },
  content: { padding:30, maxWidth:1000, margin:'0 auto',
    display:'grid', gridTemplateColumns:'1fr 2fr', gap:20 },
  formCard: { background:'white', padding:20,
    borderRadius:12, height:'fit-content' },
  taskList: { background:'white', padding:20,
    borderRadius:12 },
  taskCard: { border:'1px solid #eee', padding:15,
    borderRadius:8, marginBottom:10,
    borderLeft:'4px solid #27AE60' },
  input: { width:'100%', padding:10, margin:'6px 0',
    borderRadius:8, border:'1px solid #ddd',
    fontSize:13, boxSizing:'border-box' },
  btn: { width:'100%', padding:10, background:'#27AE60',
    color:'white', border:'none', borderRadius:8,
    cursor:'pointer', marginTop:8 },
  backBtn: { background:'transparent', color:'white',
    border:'1px solid white', padding:'6px 14px',
    borderRadius:6, cursor:'pointer' },
  select: { padding:'6px 10px', borderRadius:6,
    border:'1px solid #ddd', fontSize:12 },
  priority: { background:'#EBF5FB', color:'#0A2342',
    padding:'4px 10px', borderRadius:20, fontSize:12 }
};
